# ============================================================# factory_database.py - PostgreSQL database for multi-tenant bot factory# ============================================================import asyncpgimport loggingfrom datetime import datetime, timedeltafrom typing import List, Dict, Optional, Anyimport oslogger = logging.getLogger(__name__)class FactoryDatabase:    """Multi-tenant PostgreSQL database for bot factory"""        def __init__(self, dsn: str):        self.dsn = dsn        self.pool: Optional[asyncpg.Pool] = None        async def connect(self):        """Initialize connection pool and create factory schema"""        self.pool = await asyncpg.create_pool(self.dsn, min_size=1, max_size=20)        await self._create_factory_schema()        logger.info("Factory database connected and schema initialized")        async def close(self):        """Close connection pool"""        if self.pool:            await self.pool.close()        async def _create_factory_schema(self):        """Create factory management schema"""        async with self.pool.acquire() as conn:            # Factory bots table - stores all bot configurations            await conn.execute("""                CREATE SCHEMA IF NOT EXISTS factory;                                CREATE TABLE IF NOT EXISTS factory.bots (                    bot_id SERIAL PRIMARY KEY,                    bot_token TEXT NOT NULL UNIQUE,                    bot_name TEXT,                    channel_id BIGINT NOT NULL,                    admin_id BIGINT,                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,                    is_active BOOLEAN DEFAULT TRUE,                    config JSONB DEFAULT '{}'                );                                CREATE TABLE IF NOT EXISTS factory.payments (                    id SERIAL PRIMARY KEY,                    bot_id INTEGER NOT NULL REFERENCES factory.bots(bot_id),                    telegram_id BIGINT NOT NULL,                    amount INTEGER,                    plan TEXT,                    mpesa_ref TEXT,                    status TEXT DEFAULT 'success',                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,                    meta JSONB DEFAULT '{}'                );                                CREATE INDEX IF NOT EXISTS idx_factory_payments_bot_id ON factory.payments(bot_id);                CREATE INDEX IF NOT EXISTS idx_factory_payments_telegram_id ON factory.payments(telegram_id);                CREATE INDEX IF NOT EXISTS idx_factory_payments_created_at ON factory.payments(created_at DESC);            """)                        # Grant permissions for bot schemas            await conn.execute("GRANT CREATE ON DATABASE " + os.environ.get('POSTGRES_DB', 'botfactory') + " TO PUBLIC")        async def create_bot_schema(self, bot_id: int):        """Create isolated schema for a specific bot"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            # Create bot-specific schema            await conn.execute(f'CREATE SCHEMA IF NOT EXISTS {schema_name}')                        # Create tables in bot schema            await conn.execute(f"""                CREATE TABLE IF NOT EXISTS {schema_name}.users (                    telegram_id BIGINT PRIMARY KEY,                    first_name TEXT,                    username TEXT,                    phone TEXT,                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP                );                                CREATE TABLE IF NOT EXISTS {schema_name}.subscriptions (                    id SERIAL PRIMARY KEY,                    telegram_id BIGINT NOT NULL,                    plan TEXT NOT NULL,                    amount INTEGER NOT NULL,                    start_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,                    end_date TIMESTAMP NOT NULL,                    active BOOLEAN DEFAULT TRUE,                    reminded BOOLEAN DEFAULT FALSE,                    invite_link TEXT,                    payment_ref TEXT,                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP                );                                CREATE TABLE IF NOT EXISTS {schema_name}.pending_payments (                    checkout_request_id TEXT PRIMARY KEY,                    telegram_id BIGINT,                    phone TEXT,                    amount INTEGER,                    plan TEXT,                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP                );            """)                        logger.info(f"Created schema {schema_name} for bot {bot_id}")        # ====== FACTORY MANAGEMENT ======        async def create_bot(self, bot_token: str, channel_id: int, admin_id: int,                         bot_name: str = None, config: Dict[str, Any] = None) -> int:        """Create a new bot configuration"""        async with self.pool.acquire() as conn:            row = await conn.fetchrow("""                INSERT INTO factory.bots (bot_token, bot_name, channel_id, admin_id, config)                VALUES ($1, $2, $3, $4, $5)                RETURNING bot_id            """, bot_token, bot_name, channel_id, admin_id, config or {})                        bot_id = row['bot_id']            await self.create_bot_schema(bot_id)            return bot_id        async def get_bot(self, bot_id: int) -> Optional[Dict[str, Any]]:        """Get bot configuration"""        async with self.pool.acquire() as conn:            row = await conn.fetchrow("""SELECT * FROM factory.bots WHERE bot_id = $1""", bot_id)            return dict(row) if row else None        async def get_bot_by_token(self, bot_token: str) -> Optional[Dict[str, Any]]:        """Get bot configuration by token"""        async with self.pool.acquire() as conn:            row = await conn.fetchrow("""SELECT * FROM factory.bots WHERE bot_token = $1""", bot_token)            return dict(row) if row else None        async def get_all_bots(self) -> List[Dict[str, Any]]:        """Get all bot configurations"""        async with self.pool.acquire() as conn:            rows = await conn.fetch("""SELECT * FROM factory.bots ORDER BY created_at DESC""")            return [dict(row) for row in rows]        async def update_bot(self, bot_id: int, **kwargs) -> bool:        """Update bot configuration"""        async with self.pool.acquire() as conn:            set_clause = ", ".join([f"{k} = ${i+2}" for i, k in enumerate(kwargs.keys())])            result = await conn.execute(f"""                UPDATE factory.bots SET {set_clause} WHERE bot_id = $1            """, bot_id, *kwargs.values())            return result == "UPDATE 1"        async def delete_bot(self, bot_id: int) -> bool:        """Delete a bot and its schema"""        async with self.pool.acquire() as conn:            # Record deletion in factory            result = await conn.execute("""DELETE FROM factory.bots WHERE bot_id = $1""", bot_id)                        # Drop bot schema (optional - for security)            schema_name = f"bot_{bot_id}"            try:                await conn.execute(f'DROP SCHEMA IF EXISTS {schema_name} CASCADE')            except asyncpg.exceptions.InvalidSchemaNameError:                pass                        return result == "DELETE 1"        # ====== BOT-SPECIFIC OPERATIONS ======        async def upsert_user(self, bot_id: int, telegram_id: int, first_name: str, username: str = None):        """Add/update user in bot-specific schema"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            await conn.execute(f"""                INSERT INTO {schema_name}.users (telegram_id, first_name, username)                VALUES ($1, $2, $3)                ON CONFLICT (telegram_id) DO UPDATE SET                    first_name = EXCLUDED.first_name,                    username = EXCLUDED.username            """, telegram_id, first_name, username or "")        async def get_user(self, bot_id: int, telegram_id: int) -> Optional[Dict[str, Any]]:        """Get user from bot-specific schema"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            row = await conn.fetchrow(f"SELECT * FROM {schema_name}.users WHERE telegram_id = $1", telegram_id)            return dict(row) if row else None        async def add_pending_payment(self, bot_id: int, checkout_request_id: str, telegram_id: int,                                  phone: str, amount: int, plan: str):        """Add pending payment to bot-specific schema"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            await conn.execute(f"""                INSERT INTO {schema_name}.pending_payments                 (checkout_request_id, telegram_id, phone, amount, plan)                VALUES ($1, $2, $3, $4, $5)                ON CONFLICT (checkout_request_id) DO UPDATE SET                    telegram_id = EXCLUDED.telegram_id,                    phone = EXCLUDED.phone,                    amount = EXCLUDED.amount,                    plan = EXCLUDED.plan,                    created_at = CURRENT_TIMESTAMP            """, checkout_request_id, telegram_id, phone, amount, plan)        async def get_pending_payment(self, bot_id: int, checkout_request_id: str) -> Optional[Dict[str, Any]]:        """Get pending payment from bot-specific schema"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            row = await conn.fetchrow(                f"SELECT * FROM {schema_name}.pending_payments WHERE checkout_request_id = $1",                checkout_request_id            )            return dict(row) if row else None        async def delete_pending_payment(self, bot_id: int, checkout_request_id: str):        """Delete pending payment"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            await conn.execute(                f"DELETE FROM {schema_name}.pending_payments WHERE checkout_request_id = $1",                checkout_request_id            )        async def add_subscription(self, bot_id: int, telegram_id: int, plan: str, amount: int,                               end_date: datetime, invite_link: str, payment_ref: str) -> int:        """Add subscription to bot-specific schema"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            # Deactivate existing active subscriptions            await conn.execute(                f"UPDATE {schema_name}.subscriptions SET active = FALSE WHERE telegram_id = $1",                telegram_id            )                        # Insert new subscription            row = await conn.fetchrow(f"""                INSERT INTO {schema_name}.subscriptions                 (telegram_id, plan, amount, end_date, invite_link, payment_ref)                VALUES ($1, $2, $3, $4, $5, $6)                RETURNING id            """, telegram_id, plan, amount, end_date, invite_link, payment_ref)                        return row['id']        async def get_active_subscription(self, bot_id: int, telegram_id: int) -> Optional[Dict[str, Any]]:        """Get active subscription from bot-specific schema"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            row = await conn.fetchrow(                f"SELECT * FROM {schema_name}.subscriptions WHERE telegram_id = $1 AND active = TRUE",                telegram_id            )            return dict(row) if row else None        async def add_payment(self, bot_id: int, telegram_id: int, phone: str, amount: int,                          plan: str, mpesa_ref: str):        """Record payment in factory-wide payments table"""        async with self.pool.acquire() as conn:            await conn.execute("""                INSERT INTO factory.payments (bot_id, telegram_id, amount, plan, mpesa_ref, status, meta)                VALUES ($1, $2, $3, $4, $5, 'success', $6)            """, bot_id, telegram_id, amount, plan, mpesa_ref,                {'phone': phone, 'plan': plan})        # ====== ANALYTICS ======        async def get_bot_analytics(self, bot_id: int) -> Dict[str, Any]:        """Get analytics for a specific bot"""        schema_name = f"bot_{bot_id}"        async with self.pool.acquire() as conn:            # Users            total_users = await conn.fetchval(f"SELECT COUNT(*) FROM {schema_name}.users")                        # Subscriptions            active_subs = await conn.fetchval(                f"SELECT COUNT(*) FROM {schema_name}.subscriptions WHERE active = TRUE"            )            expired_subs = await conn.fetchval(                f"SELECT COUNT(*) FROM {schema_name}.subscriptions WHERE active = FALSE"            )                        plan_counts = await conn.fetch(f"""                SELECT plan, COUNT(*) as count                 FROM {schema_name}.subscriptions                 WHERE active = TRUE                 GROUP BY plan            """)            plan_breakdown = {row['plan']: row['count'] for row in plan_counts}                        # Revenue            result = await conn.fetchrow("""                SELECT COUNT(*) as count, COALESCE(SUM(amount), 0) as total                FROM factory.payments                 WHERE bot_id = $1 AND status = 'success'            """, bot_id)            total_revenue = result['total'] if result else 0            total_payments = result['count'] if result else 0                        # Recent payments            recent = await conn.fetch("""                SELECT p.*, u.first_name, u.username                FROM factory.payments p                JOIN {schema_name}.users u ON p.telegram_id = u.telegram_id                WHERE p.bot_id = $1                ORDER BY p.created_at DESC                LIMIT 5            """, bot_id)                        return {                'total_users': total_users,                'active_subs': active_subs,                'expired_subs': expired_subs,                'total_revenue': total_revenue,                'total_payments': total_payments,                'plan_breakdown': plan_breakdown,                'recent_payments': [dict(r) for r in recent]            }        async def get_factory_analytics(self) -> Dict[str, Any]:        """Get analytics across all bots"""        async with self.pool.acquire() as conn:            bots = await conn.fetch("SELECT * FROM factory.bots WHERE is_active = TRUE")                        total_users = 0            total_revenue = 0            total_payments = 0                        for bot in bots:                bot_id = bot['bot_id']                schema_name = f"bot_{bot_id}"                                users = await conn.fetchval(f"SELECT COUNT(*) FROM {schema_name}.users")                total_users += users or 0                                sub_counts = await conn.fetchrow("""                    SELECT COUNT(*) as count, COALESCE(SUM(amount), 0) as total                    FROM factory.payments                     WHERE bot_id = $1 AND status = 'success'                """, bot_id)                                total_payments += sub_counts['count'] or 0                total_revenue += sub_counts['total'] or 0                        return {                'bot_count': len(bots),                'total_users': total_users,                'total_payments': total_payments,                'total_revenue': total_revenue,                'bots': [dict(b) for b in bots]            }